enu li a:hover {border:0; }#menu li a:hover span {display:block;width:5em;height:2em;text-align:center;position:absolute; left:1px; top:1px; color:#FFFFFF; cursor:pointer;}--></style>xhtml<ul id="menu"><li><a href="#nogo">ITEM 1<span>ITEM 1</span></a></li><li><a href="#nogo">ITEM 2<span>ITEM 2</span></a></li><li><a href="#nogo">ITEM 3<span>ITEM 3</span></a></li><li><a href="#nogo">ITEM 4<span>ITEM 4</span></a></li><li><a href="#nogo">ITEM 5<span>ITEM 5</span></a></li></ul>Information<br>  Similar to menu nine, but this time the span information is displayed to givethe impression of an 'impression'.</p><p>19th September 2006</p><p>Updated to place menu items in a list and restyled to work in Opera 9.01</p><p>Cascading Style Sheet<br>  #menu {<br>  padding:0;<br>  margin:0;<br>  height:2em;<br>  list-style-type:none;<br>  border-left:1px solid #444;<br>  background:#dfd7ca;<br>  }<br>  #menu li {<br>  float:left; <br>  width:5em; <br>  height:2em;<br>  line-height:2em;<br>  border-right:1px solid #444;<br>  position:relative;<br>  text-align:center;<br>  }<br>  #menu li a, #menu li a:visited {<br>  display:block;<br>  text-decoration:none; <br>  color:#000;<br>  }<br>  #menu li a span, #menu li a:visited span {<br>  display:none; /* needed to trigger IE */<br>  }<br>  #menu li a:hover {<br>  border:0; <br>  }<br>  #menu li a:hover span {<br>  display:block;<br>  width:5em;<br>  height:2em;<br>  text-align:center;<br>  position:absolute; <br>  left:1px; <br>  top:1px; <br>  color:#fff; <br>  cursor:pointer;<br>  }<br>  xhtml<br>  &lt;ul id=&quot;menu&quot;&gt;<br>  &lt;li&gt;&lt;a href=&quot;#nogo&quot;&gt;ITEM 1&lt;span&gt;ITEM 1&lt;/span&gt;&lt;/a&gt;&lt;/li&gt;<br>  &lt;li&gt;&lt;a href=&quot;#nogo&quot;&gt;ITEM 2&lt;span&gt;ITEM 2&lt;/span&gt;&lt;/a&gt;&lt;/li&gt;<br>  &lt;li&gt;&lt;a href=&quot;#nogo&quot;&gt;ITEM 3&lt;span&gt;ITEM 3&lt;/span&gt;&lt;/a&gt;&lt;/li&gt;<br>  &lt;li&gt;&lt